mapper.select:
select 
from pr_import_basic_data
where create_by = #{create}
  and type = '0'
  and room_num in (
    select room_num from (
        select room_num, count(1) as cc
        from pr_import_basic_data
        where type = '0' and create_by = #{create}
        group by room_num having cc > 1
    ) aa
  )

select distinct building_id, building_name, building_code, station_id
from pr_import_basic_data
where create_by = #{create}
  and type = '0' and org_id = #{orgId}

select distinct unit_id, unit_code, unit_site, building_id, substation_id
from pr_import_basic_data
where create_by = #{create}
  and type = '0' and org_id = #{orgId}

select *
from pr_import_basic_data
where create_by = #{create}
  and type = '0' and org_id = #{orgId}

mapper.delete:
delete a from pr_user_house a left join pr_house b on b.id = a.house_id and b.org_id in
#{orgId}
where a.house_id is not null and b.id is null

mapper.insert:
insert into pr_user_house (id, user_id, house_id, create_by, create_time)
select CAST(CONV(SUBSTRING(REPLACE(UUID(), '-', ''), 18, 14), 16, 10) AS SIGNED), #{userId}, #{houseId}, #{createBy}, #{createTime}
where not exists (
    select 1 from pr_user_house where user_id = #{userId} and house_id = #{houseId}
)

insert into pr_house_expense (id, house_id, standard_id, item_group, item_code, create_by, create_time)
select CAST(CONV(SUBSTRING(REPLACE(UUID(), '-', ''), 18, 14), 16, 10) AS SIGNED), #{houseId}, s.id, s.item_group, s.item_code, #{createBy}, #{createTime}
from pr_standard s
where s.name = #{standardName}
  and s.del_flag = '0'
  and not exists (
      select 1 from pr_house_expense where house_id = #{houseId} and standard_id = s.id
  )
limit 1

insert into pr_account_balance (id, user_id, house_id, item_group, item_code, balance, create_by, create_time)
select CAST(CONV(SUBSTRING(REPLACE(UUID(), '-', ''), 18, 14), 16, 10) AS SIGNED), #{userId}, #{houseId}, e.item_group, e.item_code, #{account}, #{createBy}, #{createTime}
from pr_house_expense he
left join pr_standard e on he.standard_id = e.id
where he.house_id = #{houseId}
and not exists (
    select 1 from pr_account_balance where user_id = #{userId} and house_id = #{houseId}
)
limit 1
